const run = $input.first().json;
const config = $('Setup Config').first().json;

return [{
  json: {
    pipeline_run_id: run.id,
    sop_id: run.sop_id,
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_ANON_KEY: config.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: config.SUPABASE_SERVICE_ROLE_KEY,
    GEMINI_API_KEY: config.GEMINI_API_KEY
  }
}];

const step = $input.first().json;
const config = $('Extract Run Info').first().json;

return [{
  json: {
    step_id: step.id,
    sequence: step.sequence,
    timestamp_start: step.timestamp_start,
    timestamp_end: step.timestamp_end,
    gemini_description: step.gemini_description || null,
    sop_id: config.sop_id,
    pipeline_run_id: config.pipeline_run_id,
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_ANON_KEY: config.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: config.SUPABASE_SERVICE_ROLE_KEY,
    GEMINI_API_KEY: config.GEMINI_API_KEY
  }
}];

const lines = $input.all().map(i => i.json);
const ctx = $('Prepare Step Context').first().json;

const minutes = (s) => {
  const m = Math.floor(s / 60);
  const sec = Math.floor(s % 60);
  return `${m}:${sec.toString().padStart(2,'0')}`;
};

let transcriptText;
if (lines.length > 0) {
  transcriptText = lines.map(l => `[${minutes(l.timestamp_sec)}] ${l.speaker}: ${l.content}`).join('\n');
} else if (ctx.gemini_description) {
  transcriptText = `(No transcript available for this timestamp. Screen annotation: ${ctx.gemini_description})`;
} else {
  transcriptText = `(No transcript available. This is step ${ctx.sequence} of the procedure at timestamp ${minutes(ctx.timestamp_start)})`;
}

const prompt = `You are creating a Standard Operating Procedure (SOP) from a Knowledge Transfer (KT) session recording for a hotel BPO process.\n\nFor Step ${ctx.sequence} (at video timestamp ${minutes(ctx.timestamp_start)}), generate the following based on the context below:\n1. title: A concise action-oriented step title (max 8 words, starts with a verb like Open, Navigate, Update, Verify, Copy, etc.)\n2. description: A clear 1-2 sentence instruction in imperative form describing exactly what to do\n3. sub_steps: An array of 2-5 specific micro-actions in sequence\n\nContext for this step:\n${transcriptText}\n\nRespond ONLY with valid JSON, no markdown, no code blocks:\n{"title":"...","description":"...","sub_steps":["action 1","action 2"]}`;

return [{
  json: {
    step_id: ctx.step_id,
    sequence: ctx.sequence,
    sop_id: ctx.sop_id,
    pipeline_run_id: ctx.pipeline_run_id,
    SUPABASE_URL: ctx.SUPABASE_URL,
    SUPABASE_ANON_KEY: ctx.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: ctx.SUPABASE_SERVICE_ROLE_KEY,
    GEMINI_API_KEY: ctx.GEMINI_API_KEY,
    prompt
  }
}];

const response = $input.first().json;
const ctx = $('Build Gemini Prompt').first().json;

let parsed;
try {
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { title: `Step ${ctx.sequence}`, description: null, sub_steps: [] };
}

const title = parsed.title || `Step ${ctx.sequence}`;
const description = parsed.description || null;
const sub_steps = Array.isArray(parsed.sub_steps) ? parsed.sub_steps : [];

return [{
  json: {
    step_id: ctx.step_id,
    sop_id: ctx.sop_id,
    pipeline_run_id: ctx.pipeline_run_id,
    SUPABASE_URL: ctx.SUPABASE_URL,
    SUPABASE_ANON_KEY: ctx.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: ctx.SUPABASE_SERVICE_ROLE_KEY,
    title,
    description,
    sub_steps
  }
}];

const lines = $input.all().map(i => i.json);
const config = $('Extract Run Info').first().json;
const meta = $('Fetch SOP Metadata').first().json;

const minutes = (s) => {
  const m = Math.floor(s / 60);
  const sec = Math.floor(s % 60);
  return `${m}:${sec.toString().padStart(2,'0')}`;
};

const transcript = lines
  .slice(0, 400)
  .map(l => `[${minutes(l.timestamp_sec)}] ${l.speaker}: ${l.content}`)
  .join('\n');

const processName = meta.process_name || meta.title || 'Unknown Process';
const clientName = meta.client_name || 'Unknown Client';
const participants = Array.isArray(meta.meeting_participants)
  ? meta.meeting_participants.join(', ')
  : (meta.meeting_participants || 'Unknown');

const prompt = `You are generating structured SOP sections from a Knowledge Transfer (KT) session transcript for a hotel BPO (Business Process Outsourcing) process.\n\nProcess: ${processName}\nClient: ${clientName}\nParticipants: ${participants}\n\nFull transcript:\n${transcript}\n\nBased on this transcript, generate the following SOP sections. Be specific and accurate — extract real information from the transcript, do not invent details.\n\nReturn ONLY valid JSON in this exact format (no markdown, no code blocks):\n{\n  "purpose": "2-3 sentence description of the purpose, objective, and scope of this process",\n  "inputs": ["what is needed to start this process"],\n  "process_summary": ["high-level step 1", "high-level step 2"],\n  "outputs": ["what is produced or delivered by this process"],\n  "risks": [{"risk": "risk description", "impact": "High/Medium/Low", "mitigation": "how to mitigate"}],\n  "training_prereqs": ["prerequisite knowledge or system access needed"],\n  "software_access": [{"software": "system name", "access_level": "Read/Write/Admin", "purpose": "why needed"}],\n  "comm_matrix_infomate": [{"role": "InfoMate team role", "responsibility": "their responsibility", "frequency": "Daily/Weekly/Monthly/Ad-hoc"}],\n  "comm_matrix_client": [{"role": "client-side role", "responsibility": "their responsibility", "frequency": "Daily/Weekly/Monthly/Ad-hoc"}],\n  "quality_params": [{"parameter": "quality metric", "target": "target value", "measurement": "how measured"}],\n  "quality_sampling": "description of quality review sampling approach and percentage",\n  "sow": [{"activity": "activity name", "description": "what InfoMate does", "owner": "InfoMate/Client/Both"}],\n  "baseline_target": [{"metric": "metric name", "baseline": "current performance", "target": "desired target"}],\n  "challenges": "description of known challenges, exceptions, or issues with this process",\n  "improvements": "suggested process improvements or automation opportunities identified from the session"\n}`;

return [{
  json: {
    sop_id: config.sop_id,
    pipeline_run_id: config.pipeline_run_id,
    SUPABASE_URL: config.SUPABASE_URL,
    SUPABASE_ANON_KEY: config.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: config.SUPABASE_SERVICE_ROLE_KEY,
    GEMINI_API_KEY: config.GEMINI_API_KEY,
    prompt
  }
}];

const response = $input.first().json;
const ctx = $('Build Sections Prompt').first().json;

const SECTION_TEMPLATES = {
  purpose:              { title: 'Purpose/Objective/Scope',               order: 1,  type: 'text' },
  inputs:               { title: 'Input',                                  order: 2,  type: 'list' },
  process_summary:      { title: 'Process Description',                    order: 3,  type: 'list' },
  outputs:              { title: 'Output',                                  order: 4,  type: 'list' },
  risks:                { title: 'Description of Risks',                    order: 5,  type: 'table' },
  training_prereqs:     { title: 'Training Prerequisites',                  order: 6,  type: 'list' },
  software_access:      { title: 'Software Applications/Access Levels',     order: 7,  type: 'table' },
  comm_matrix_infomate: { title: 'Communication Matrix - InfoMate',         order: 10, type: 'table' },
  comm_matrix_client:   { title: 'Communication Matrix - Client',           order: 11, type: 'table' },
  quality_params:       { title: 'Quality Parameters',                      order: 13, type: 'table' },
  quality_sampling:     { title: 'Quality Sampling Percentage',             order: 14, type: 'text' },
  sow:                  { title: 'Detailed Statement of Work',              order: 15, type: 'table' },
  baseline_target:      { title: 'Baselining and Target',                   order: 16, type: 'table' },
  challenges:           { title: 'Challenges',                              order: 17, type: 'text' },
  improvements:         { title: 'Process Improvements',                    order: 18, type: 'text' }
};

let parsed;
try {
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {};
}

const sections = [];
for (const [key, tmpl] of Object.entries(SECTION_TEMPLATES)) {
  const value = parsed[key];
  if (!value) continue;

  const isText = tmpl.type === 'text';
  const contentText = isText ? (typeof value === 'string' ? value : JSON.stringify(value)) : null;
  const contentJson = !isText ? (Array.isArray(value) ? value : [value]) : null;

  sections.push({
    sop_id: ctx.sop_id,
    section_key: key,
    section_title: tmpl.title,
    display_order: tmpl.order,
    content_type: tmpl.type,
    content_text: contentText,
    content_json: contentJson,
    SUPABASE_URL: ctx.SUPABASE_URL,
    SUPABASE_ANON_KEY: ctx.SUPABASE_ANON_KEY,
    SUPABASE_SERVICE_ROLE_KEY: ctx.SUPABASE_SERVICE_ROLE_KEY
  });
}

return sections.map(s => ({ json: s }));
